+				Confidence:   0.85,
+			},
+			providerUsage: nil,
+			wantMin:       75,
+			wantMax:       75,
+		},
+		{
+			name: "context low while working",
+			localState: &PaneWorkStatus{
+				AgentType:    "cc",
+				IsWorking:    true,
+				IsContextLow: true,
+				Confidence:   0.85,
+			},
+			providerUsage: nil,
+			wantMin:       90,
+			wantMax:       90,
+		},
+		{
+			name: "unknown agent type",
+			localState: &PaneWorkStatus{
+				AgentType:  "unknown",
+				IsIdle:     true,
+				Confidence: 0.7,
+			},
+			providerUsage: nil,
+			wantMin:       85,
+			wantMax:       85,
+		},
+		{
+			name: "low confidence",
+			localState: &PaneWorkStatus{
+				AgentType:  "cc",
+				IsIdle:     true,
+				Confidence: 0.3,
+			},
+			providerUsage: nil,
+			wantMin:       90,
+			wantMax:       90,
+		},
+		{
+			name: "provider at moderate usage",
