+	if got.PrimaryWindow.WindowMinutes == nil || *got.PrimaryWindow.WindowMinutes != 480 {
+		t.Errorf("WindowMinutes = %v, want 480", got.PrimaryWindow.WindowMinutes)
+	}
+}
+
+func TestUpdateProviderSummary(t *testing.T) {
